import pandas as pd
import matplotlib.pyplot as plt
import numpy as np

# Assume df1, df2, df3 are the three datasets from different databases
databases = {"Google scholar": df1, "Scopus": df2, "Web of science": df3}

# Define year range from 2000 to the latest year across all datasets
max_year = max(df1['Year'].max(), df2['Year'].max(), df3['Year'].max())
year_range = list(range(2000, int(max_year) + 1))

# Create a DataFrame to store counts for each database
yearly_counts = pd.DataFrame(index=year_range)

# Populate counts for each database
for name, df in databases.items():
    df['Year'] = pd.to_numeric(df['Year'], errors='coerce').dropna().astype(int)  # Ensure Year is int
    yearly_counts[name] = df['Year'].value_counts().reindex(year_range, fill_value=0)  # Align with full range

# Plot grouped bar chart
plt.figure(figsize=(12, 6))
bar_width = 0.30  # Adjust spacing between bars
x_indexes = np.arange(len(year_range))  # X-axis positions

# Plot each database's bars with different colors
colors = ['royalblue', 'darkorange', 'green']  # Define colors for databases
for i, (name, color) in enumerate(zip(databases.keys(), colors)):
    plt.bar(x_indexes + i * bar_width, yearly_counts[name], width=bar_width, label=name, color=color)

# Customize plot
plt.xlabel("Year")
plt.ylabel("Number of Publications")
plt.title("Number of Publications Over Time (Across Databases)")
plt.xticks(x_indexes + bar_width, year_range, rotation=45)  # Center tick labels
plt.legend()  # Show legend for database names
plt.grid(axis='y', linestyle='--', alpha=0.7)

# Show the plot
plt.show()

plt.figure(figsize=(12, 6))
yearly_counts.plot(kind='bar', stacked=True, color=['royalblue', 'darkorange', 'green'], width=0.8)

plt.xlabel("Year")
plt.ylabel("Number of Publications")
plt.title("Number of Publications Over Time (Stacked by Database)")
