import matplotlib.pyplot as plt

# Define total papers, removed papers, and calculate remaining papers
total_papers = {
    "Google Scholar": 961,
    "Scopus": 730,
    "Web of Science": 54
}

removed_papers = {
    "Google Scholar": 934,
    "Scopus": 666,
    "Web of Science": 35
}

remaining_papers = {db: total_papers[db] - removed_papers[db] for db in total_papers}

# Convert dictionaries to lists for plotting
databases = list(total_papers.keys())
total_values = list(total_papers.values())
removed_values = list(removed_papers.values())
remaining_values = list(remaining_papers.values())

# Plot bar chart
fig, ax = plt.subplots(figsize=(9, 5))
bar_width = 0.3
x = range(len(databases))

# Plot bars for total, removed, and remaining papers
bars1 = ax.bar([i - bar_width for i in x], total_values, width=bar_width, color='royalblue', label='Total papers')
bars2 = ax.bar(x, removed_values, width=bar_width, color='red', label='Removed papers')
bars3 = ax.bar([i + bar_width for i in x], remaining_values, width=bar_width, color='green', label='used papers')

# Add numbers on top of bars
for bars in [bars1, bars2, bars3]:
    for bar in bars:
        ax.text(bar.get_x() + bar.get_width()/2, bar.get_height(), f'{int(bar.get_height()):,}', ha='center', va='bottom')

# Labels and title
ax.set_xlabel("Database")
ax.set_ylabel("Number of Papers")
ax.set_title("Paper screening from different databases")
ax.set_xticks(x)
ax.set_xticklabels(databases)
ax.legend(loc="upper right")
ax.grid(axis='y', linestyle='', alpha=0.7)

# Show plot
plt.show()

import pandas as pd
import matplotlib.pyplot as plt

# Assuming each dataframe has a 'Database' column
df1['Database'] = "Google Scholar"
df2['Database'] = "Scopus"
df3['Database'] = "Web of Science"

# Combine all databases
all_data = pd.concat([df1, df2, df3])

# Count the number of papers in each database
paper_counts = all_data['Database'].value_counts()

# Define colors
colors = ['lightblue', 'peachpuff', 'lightgreen']

# Define explode effect (to highlight all slices slightly)
explode = (0.05, 0.05, 0.05)

# Function to display both percentage and actual counts
def autopct_format(pct, values):
    absolute = int(round(pct / 100. * sum(values)))  # Convert percentage to actual count
    return f"{pct:.1f}%\n({absolute:,})"  # Format with comma separator

# Plot pie chart
plt.figure(figsize=(9, 9))
plt.pie(paper_counts, labels=paper_counts.index, autopct=lambda pct: autopct_format(pct, paper_counts),
        colors=colors, startangle=130, explode=explode, shadow=True, wedgeprops={'edgecolor': 'black'})

# Show plot
plt.show()

import pandas as pd
import matplotlib.pyplot as plt

# Ensure 'Cited by' and 'Year' columns are numeric
for df in [df1, df2, df3]:
    df['Cited by'] = pd.to_numeric(df['Cited by'], errors='coerce')  # Convert to numeric, handle NaN
    df['Year'] = pd.to_numeric(df['Year'], errors='coerce')  # Convert to numeric, handle NaN

# Combine all databases
all_data = pd.concat([df1, df2, df3])

# Drop NaN values in 'Cited by' and 'Year'
all_data = all_data.dropna(subset=['Cited by', 'Year'])

# Filter only years from 2000 to 2025
all_data = all_data[(all_data['Year'] >= 2000) & (all_data['Year'] <= 2025)]

# Sum citations per year across all databases
total_citations_per_year = all_data.groupby('Year')['Cited by'].sum() / 1e4  # Convert to ×10⁴

# Ensure missing years appear with zero citations
all_years = pd.Series(0, index=range(2000, 2026))  # Create full range of years
total_citations_per_year = all_years.add(total_citations_per_year, fill_value=0)  # Merge with actual data

# Plot bar chart
plt.figure(figsize=(10, 6))
plt.bar(total_citations_per_year.index, total_citations_per_year.values, color='royalblue', label="Citations")

# Labels and title
plt.xlabel("Year")
plt.ylabel("Number of Citations (×10⁴)")
plt.title("Total Manuscript Citations Per Year (2000 - 2025)")
plt.xticks(range(2000, 2026, 2), rotation=45)  # Show every 2nd year for readability
plt.grid(axis='y', linestyle='--', alpha=0.7)

# Add legend
plt.legend()

# Show plot
plt.show()

