import matplotlib.pyplot as plt
import numpy as np

# Sample data: average theoretical rigor scores (0-18 scale) for each technique and method.
# Each list contains scores for [RL, GT, GNN] respectively.
scores = {
    'Ecological Relevance': [12, 14, 10],
    'Theoretical Foundations': [15, 13, 12],
    'Uncertainty Quantification': [9, 8, 11],
    'Scalability': [10, 12, 9],
    'Stakeholder Utility': [13, 15, 14],
    'Interpretability': [11, 9, 10]
}

techniques = list(scores.keys())
colors = ['tab:blue', 'tab:orange', 'tab:green', 'tab:red', 'tab:purple', 'tab:brown']
markers = ['o', 's', 'D', '^', 'v', 'P']

# Numeric mapping for method categories
method_map = {'RL': 1, 'GT': 2, 'GNN': 3}
x_positions = np.array([method_map['RL'], method_map['GT'], method_map['GNN']])

plt.figure(figsize=(8,6))
plt.grid(True, linestyle='--', linewidth=0.5, alpha=0.7)

# Plot each technique as a separate scatter series
for i, technique in enumerate(techniques):
    y_values = scores[technique]
    plt.scatter(x_positions, y_values, label=technique, color=colors[i], marker=markers[i], s=100)

# Add trend line (linear fit) across all points
all_x = []
all_y = []
for y_vals in scores.values():
    all_x.extend(x_positions)
    all_y.extend(y_vals)
coeffs = np.polyfit(all_x, all_y, 1)
trend_line = np.poly1d(coeffs)
xs = np.linspace(1, 3, 100)
plt.plot(xs, trend_line(xs), color='gray', linestyle='--', linewidth=1, label='Trend Line')

# Customize plot
plt.xticks([1, 2, 3], ['RL', 'GT', 'GNN'])
plt.xlabel('Method Category')
plt.ylabel('Average Theoretical Rigor Score (0–18)')
plt.title('Theoretical Rigor Scores by Method Category')
plt.ylim(0, 18)
plt.legend(loc='upper left', fontsize=9, framealpha=0.9)
plt.tight_layout()

plt.show()

import matplotlib.pyplot as plt
import numpy as np

# Example data: average theoretical rigor scores for each method (RL, GT, GNN) and technique
techniques = [
    'Ecological Relevance',
    'Theoretical Foundations',
    'Uncertainty Quantification',
    'Scalability',
    'Stakeholder Utility',
    'Interpretability'
]
RL_scores  = [12, 15, 10,  8, 14, 13]   # Reinforcement Learning scores
GT_scores  = [10, 12,  9, 11, 12,  9]   # Graph Theory scores
GNN_scores = [14, 16, 11, 12, 13, 15]   # Graph Neural Network scores

# Numeric positions for the categorical techniques
x = np.arange(len(techniques))

# Marker shapes for each technique (one shape per technique)
shapes = ['o', 's', '^', 'D', 'P', 'X']  # circle, square, triangle_up, diamond, plus (pentagon), X (cross)
# Colors for each method
color_RL = 'blue'
color_GT = 'green'
color_GNN = 'orange'

plt.figure(figsize=(8,6))

# Plot one point for each method at each technique
for i in range(len(techniques)):
    plt.scatter(x[i], RL_scores[i],  marker=shapes[i], color=color_RL,  s=100, zorder=3)
    plt.scatter(x[i], GT_scores[i],  marker=shapes[i], color=color_GT,  s=100, zorder=3)
    plt.scatter(x[i], GNN_scores[i], marker=shapes[i], color=color_GNN, s=100, zorder=3)

# Add overall trend line (linear fit across all points)
all_x = np.concatenate([x, x, x])
all_y = np.concatenate([RL_scores, GT_scores, GNN_scores])
# Fit a first-degree polynomial (linear)
coeff = np.polyfit(all_x, all_y, 1)
poly = np.poly1d(coeff)
plt.plot(x, poly(x), color='red', linestyle='--', label='Trend Line', zorder=2)

# Axis labels and title
plt.xticks(x, techniques, rotation=45, ha='right')
plt.xlabel('Optimization Technique')
plt.ylabel('Theoretical Rigor Score (0–18)')
plt.title('Theoretical Rigor Scores by Method and Technique')

# Create custom legend entries for methods (color)
from matplotlib.lines import Line2D
method_handles = [
    Line2D([0], [0], marker='o', color='w', markerfacecolor=color_RL,  markersize=10, label='Reinforcement Learning'),
    Line2D([0], [0], marker='o', color='w', markerfacecolor=color_GT,  markersize=10, label='Graph Theory'),
    Line2D([0], [0], marker='o', color='w', markerfacecolor=color_GNN, markersize=10, label='Graph Neural Network')
]
legend1 = plt.legend(handles=method_handles, title='Method', loc='upper left')

# Create custom legend entries for techniques (marker shape)
technique_handles = [
    Line2D([0], [0], marker=shapes[i], color='k', linestyle='None', markersize=10, label=techniques[i])
    for i in range(len(techniques))
]
plt.legend(handles=technique_handles, title='Technique', loc='upper right')
plt.gca().add_artist(legend1)

plt.tight_layout()
plt.show()

