x = np.arange(len(dimensions))

for i, method in enumerate(methods):
    ax.plot(
        df_scores[method],
        x + i * 0.2 - 0.2,  # slight vertical offset
        marker=markers[i],
        color=colors[i],
        label=method,
        linestyle='None',
        markersize=8
    )

ax.set_yticks(x)
ax.set_yticklabels(dimensions)
ax.invert_yaxis()
ax.set_xlabel("Score (0–3)")
ax.set_title("Forest Plot: Method Performance on Rigor Dimensions")
ax.legend(loc='lower right')
plt.grid(True, linestyle='--', alpha=0.5)
plt.tight_layout()
