import pandas as pd
import matplotlib.pyplot as plt
import numpy as np

# -------------------------
# 1. Create example dataset
# -------------------------
fake_data = pd.DataFrame({
    "Study": ["RL1", "RL2", "RL3", "GT1", "GT2", "GT3", "GNN1", "GNN2"],
    "Method": ["RL", "RL", "RL", "GT", "GT", "GT", "GNN", "GNN"],
    "Ecological_Relevance": [3, 2, 2, 3, 1, 2, 2, 3],
    "Theoretical_Foundations": [2, 2, 3, 1, 1, 2, 3, 2],
    "Uncertainty_Quantification": [1, 0, 1, 0, 0, 1, 1, 2],
    "Scalability": [3, 2, 2, 2, 2, 1, 3, 3],
    "Stakeholder_Utility": [2, 1, 1, 1, 0, 0, 2, 2],
    "Interpretability": [3, 3, 2, 2, 1, 2, 3, 3]
})

# Calculate overall score
fake_data["Overall_Score"] = fake_data[
    ["Ecological_Relevance", "Theoretical_Foundations",
     "Uncertainty_Quantification", "Scalability",
     "Stakeholder_Utility", "Interpretability"]
].sum(axis=1)

# -------------------------
# 2. Summary statistics per method
# -------------------------
summary = fake_data.groupby("Method").agg(
    mean_score=("Overall_Score", "mean"),
    sd_score=("Overall_Score", "std"),
    min_score=("Overall_Score", "min"),
    max_score=("Overall_Score", "max")
).reset_index()

print("\nSummary statistics per method:")
print(summary)

# -------------------------
# 3. Boxplot for overall scores
# -------------------------
plt.figure(figsize=(6,4))
fake_data.boxplot(column="Overall_Score", by="Method", grid=False)
plt.title("Overall Theoretical Rigour by Method")
plt.suptitle("")  # remove automatic title
plt.ylabel("Score (0–18)")
plt.show()

# -------------------------
# 4. Radar chart of mean scores per criterion
# -------------------------
criteria = ["Ecological_Relevance", "Theoretical_Foundations",
            "Uncertainty_Quantification", "Scalability",
            "Stakeholder_Utility", "Interpretability"]

# Compute means
mean_scores = fake_data.groupby("Method")[criteria].mean()

# Radar setup
angles = np.linspace(0, 2*np.pi, len(criteria), endpoint=False).tolist()
angles += angles[:1]  # close the loop

fig, ax = plt.subplots(figsize=(6,6), subplot_kw=dict(polar=True))
for method in mean_scores.index:
    values = mean_scores.loc[method].tolist()
    values += values[:1]  # close loop
    ax.plot(angles, values, label=method)
    ax.fill(angles, values, alpha=0.25)

ax.set_xticks(angles[:-1])
ax.set_xticklabels(criteria)
ax.set_yticks(range(0, 4))
ax.set_title("Mean Theoretical Rigour Profile by Method")
ax.legend()
plt.show()

# -------------------------
# 5. Simple forest plot
# -------------------------
plt.figure(figsize=(6,4))
for i, row in enumerate(fake_data.sort_values("Overall_Score").itertuples()):
    plt.errorbar(row.Overall_Score, i, xerr=0.5, fmt='o', label=row.Method if i == 0 else "")
plt.axvline(x=summary["mean_score"].mean(), color='red', linestyle='--', label="Overall Mean")
plt.yticks(range(len(fake_data)), fake_data.sort_values("Overall_Score")["Study"])
plt.xlabel("Overall Theoretical Rigour")
plt.title("Forest Plot of Study Scores")
plt.legend()
plt.show()



