# Filter only 2025 papers
df1_2025 = df1[df1["Year"] == 2025]
df2_2025 = df2[df2["Year"] == 2025]

# Get unique titles from both
titles1 = set(df1_2025["Title"].str.strip().str.lower())  # normalize case/spacing
titles2 = set(df2_2025["Title"].str.strip().str.lower())

# Find titles that are different (symmetric difference)
different_titles = titles1.symmetric_difference(titles2)

# Create datasets of different papers
df1_diff = df1_2025[df1_2025["Title"].str.strip().str.lower().isin(different_titles)]
df2_diff = df2_2025[df2_2025["Title"].str.strip().str.lower().isin(different_titles)]

# Combine both into one dataset of different papers
different_papers = pd.concat([df1_diff, df2_diff], ignore_index=True)

# Save result
different_papers.to_excel("different_papers.xlsx", index=False)

print("✅ Dataset of different papers saved as 'different_papers.xlsx'")

