"""Check overlapping"""

import pandas as pd

# Load the two Excel datasets
feb_df = pd.read_excel("GOOGLE_SCHOLAR_NEW_01_10_2025(2025 papers).xlsx")   # 911 papers
oct_df = pd.read_excel("SCOPUS_new_papers_october(82 NEW PAPERS).xlsx")   # 961 papers

# Keep only 2025 papers
feb_2025 = feb_df[feb_df["Year"] == 2025]
oct_2025 = oct_df[oct_df["Year"] == 2025]

# Normalize titles (lowercase + strip spaces)
feb_titles = set(feb_2025["Title"].str.strip().str.lower())
oct_titles = set(oct_2025["Title"].str.strip().str.lower())

# Find OVERLAPPING papers (present in both Feb and Oct datasets)
overlap_titles = feb_titles & oct_titles

# Extract rows for those overlapping papers
overlap_papers = oct_2025[oct_2025["Title"].str.strip().str.lower().isin(overlap_titles)]

# Save result
overlap_papers.to_excel("overlapping_papers.xlsx", index=False)

print(f"✅ Found {len(overlap_papers)} overlapping papers between February and October 2025.")



import matplotlib.pyplot as plt

# Real data from classification
labels = ['Habitat Connectivity', 'Other', 'Ecological Monitoring', 'Biodiversity Conservation', 'Species Interactions/Food Webs', 'Animal Behaviour', 'Environmental Forecasting', 'Fisheries Management']
sizes = [50.8, 15.6, 8.2, 6.6, 5.7, 5.7, 4.9, 2.5]  # Percentages
colors = ['#90EE90', '#D3D3D3', '#87CEEB', '#FFA07A', '#FFD700', '#98FB98', '#FF8C00', '#A9A9A9']  # Gradient like the example: greens, grays, blues, oranges, yellows

# Create the pie chart
fig, ax = plt.subplots(figsize=(8, 6))
wedges, texts, autotexts = ax.pie(sizes, labels=None, autopct='%1.1f%%', startangle=90, colors=colors,
                                  pctdistance=0.85, textprops={'fontsize': 10})

# Bold percentages
plt.setp(autotexts, size=10, weight="bold", color="black")

# Legend on the right with category (percentage)
